package com.cognizant.ems.model; import java.time.*; import java.util.*; import jakarta.persistence.*; import org.springframework.data.annotation.*; import org.springframework.data.jpa.domain.support.*;
@Entity @EntityListeners(AuditingEntityListener.class) @NamedQuery(name="Department.byName",query="select d from Department d where d.name=:name") public class Department {@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private String name; @OneToMany(mappedBy="department",cascade=CascadeType.ALL) private List<Employee> employees=new ArrayList<>(); @CreatedDate private Instant createdAt;@LastModifiedDate private Instant updatedAt; public Long getId(){return id;}public String getName(){return name;}public void setName(String n){name=n;}public List<Employee> getEmployees(){return employees;}}
